function [ dataf ] = pf2_hpf( data,ft,fs,freq_cut,Nf ,NaN_mode)% inputs ------------------------% data: data to be filtered% ft: filter type% fs: sampling freq.% freq_cut: cut-off frequency% Nf: filter length% outputs -----------------------% dataf: filtered data%--------------------------------% lpf function designs highpass FIR filter with the specified cut-off frequency and length.% It filters the data columnwise as its output%--------------------------------if(nargin<6)	NaN_mode='Piecewise';end[Mini,Nini]=size(data);if Mini==1 %if the data is a row vector converts it to column vector    data=data';end[M,N]=size(data);%-----------------------------------------------------------------% High-pass Filter design%-----------------------------------------------------------------half_fs = fs/2;    %half of sampling freq. equal to piif ft==1    [b,a] = fir1(Nf,freq_cut/half_fs,'high');  % use FIR1 to obtain linear phase filter; b=impulse response                                     elseif ft==3    [b,a] = butter(Nf,freq_cut/half_fs,'high');                     end%-----------------------------------------------------------------% Filter the data%-----------------------------------------------------------------%H = fft(b',2*(M+Nf));           %frequency domain filter%H = freqz(b,a,2*(M+Nf),'whole');           %frequency domain filter%H=H/(H(1));%Data = fft(data,2*(M+Nf));      %frequency domain data%Dataf = (H * ones(1,N)) .* Data;  %frequency domain filtered data%datad = ifft(Dataf);              %time domain filtered data   %dataf = (real(datad(Nf/2:M+Nf/2-1,1:N))); %adjustment for time shifting caused by the filterif(size(data,1)>3*Nf)    switch(NaN_mode)		case 'Interpolate'			try				dataf=pf2_base.filtfilt_interp(b,a,data);			catch				dataf=pf2_base.external.filtfilt_classic(b,a,data); % Use matlab 2018a filtfilt if current version fails due to nans			end		case 'Piecewise'			try				dataf=pf2_base.filtfilt_piecewise(b,a,data,3*Nf);			catch				dataf=pf2_base.external.filtfilt_classic(b,a,data); % Use matlab 2018a filtfilt if current version fails due to nans			end		case 'Leave'			try				dataf=filtfilt(b,a,data);			catch				dataf=pf2_base.external.filtfilt_classic(b,a,data); % Use matlab 2018a filtfilt if current version fails due to nans            end	endelse    dataf=nan(size(data));     warning('LPF: Datasize must be larger than 3*filter length (%i samples)',Nf);endif Mini==1 %if the data is a row vector converts it to column vector    dataf=dataf';end